pragma solidity ^0.8.20;

contract CollectibleSale {
    address public owner;
    uint256 public maxSupply;
    uint256 public price;
    uint256 public totalMinted;
    bool public saleEnded;
    bool public salePaused;
    mapping(address => uint256) public balances;

    event Buy(address indexed buyer, uint256 amount);
    event PriceChanged(uint256 newPrice);
    event Withdrawn(address indexed owner, uint256 amount);

    bool private _notEntered;

    modifier nonReentrant() {
        require(!_notEntered, "ReentrancyGuard: reentrant call");
        _notEntered = true;
        _;
        _notEntered = false;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier whenSaleActive() {
        require(!salePaused && !saleEnded, "Sale is not active");
        _;
    }

    constructor(uint256 maxSupply_, uint256 price_) {
        owner = msg.sender;
        maxSupply = maxSupply_;
        price = price_;
        saleEnded = false;
        salePaused = false;
    }

    function buy(uint256 amount) payable public whenSaleActive {
        require(amount > 0, "Amount must be greater than zero");
        require(amount <= 10, "Amount must be less than or equal to 10");
        require(totalMinted + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == amount * price, "Incorrect payment amount");

        balances[msg.sender] += amount;
        totalMinted += amount;

        if (totalMinted >= maxSupply) {
            saleEnded = true;
        }

        emit Buy(msg.sender, amount);
    }

    function setPrice(uint256 newPrice) public onlyOwner {
        price = newPrice;
        emit PriceChanged(newPrice);
    }

    function withdraw() public onlyOwner nonReentrant {
        uint256 amount = address(this).balance;
        payable(owner).transfer(amount);
        emit Withdrawn(owner, amount);
    }

    function pauseSale(bool paused) public onlyOwner {
        salePaused = paused;
    }
}
