    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier whenSaleActive() {
        require(!salePaused && !saleEnded, "Sale is not active");
        _;
    }

    constructor(uint256 maxSupply_, uint256 price_) {
        owner = msg.sender;
        maxSupply = maxSupply_;
        price = price_;
        saleEnded = false;
        salePaused = false;
    }

    function buy(uint256 amount) payable public whenSaleActive {
        require(amount > 0, "Amount must be greater than zero");
        require(amount <= 10, "Amount must be less than or equal to 10");
        require(totalMinted + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == amount * price, "Incorrect payment amount");

