        totalMinted += amount;

        if (totalMinted >= maxSupply) {
            saleEnded = true;
        }

        emit Buy(msg.sender, amount);
    }

    function setPrice(uint256 newPrice) public onlyOwner {
        price = newPrice;
        emit PriceChanged(newPrice);
    }

